LAYER
	NAME "parque"
	GROUP "Catastro"
	TYPE line
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/kaypacha/parque.html"
	#FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, id_ubigeo, cod_parque, id_lote, id_parque, nomb_parque, area_grafi, peri_grafi, geom FROM geo.tg_parque) as kaypacha using unique gid using srid=32718"
	INCLUDE "configuracion/postgresql_kaypacha.map"
	PROJECTION
		"init=epsg:32718"
	END
	CLASSITEM "gid"
	METADATA
		"wms_group_title" "Predio urbano"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Parque"
		"wms_abstract" "Parque || Municipalidad Distrital de Machupicchu - Cusco :: Perú"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_credit" "Kaypacha"
		"wms_extent" "760133.1070907626 8524431.575746633 783630.700165417 8552463.306938704"
		"wms_srs" "EPSG:32718"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
		NAME "Parque"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 0 255 63
			WIDTH 1
		END
	END
END # Layer
